//! Roadmap — a public, living list of improvements we know we want.
//!
//! Authored as `Section { Item { … } }` composed with `ui!`. `Section`
//! and `Item` are `#[component]`s, so their tags and `BuildElement`
//! impls are generated by the macro.

use runtime_core::{component, ui, Element, Ref, ViewHandle};
use idea_ui::{typography_kind, Stack, StackAxis, StackGap, Tag, Typography};

use crate::pages::common::{PageHeader, PageSection};
use crate::shell::{layout_with_toc, TocEntry};

pub fn page() -> Element {
    let docs_ref: Ref<ViewHandle> = Ref::new();
    let a11y_ref: Ref<ViewHandle> = Ref::new();

    let toc = vec![
        TocEntry { handle: docs_ref, label: "Docs & learning" },
        TocEntry { handle: a11y_ref, label: "Accessibility" },
    ];

    let docs_section = ui! {
        Section(
            title = "Docs & learning".to_string(),
            intro = "Making the framework easier to learn end-to-end.".to_string(),
        ) {
            Item(
                title = "Interactive tutorial previews".to_string(),
                status = "In progress".to_string(),
                tone = in_progress(),
            ) {
                Typography(
                    content = "Live, runnable previews embedded in the concepts tutorial, \
                        backed by the in-browser fiddle. Today's lessons are \
                        read-and-understand; editable, running examples are the next \
                        step.".to_string(),
                    muted = true,
                )
            }
            Item(
                title = "Advanced tutorial tracks".to_string(),
                status = "Planned".to_string(),
                tone = planned(),
            ) {
                Typography(
                    content = "Deep-dive walkthroughs: implementing a custom backend function \
                        by function, building interactive CLI tools on the terminal backend, \
                        and rendering to microcontrollers via the CPU renderer.".to_string(),
                    muted = true,
                )
            }
        }
    };

    let a11y_section = ui! {
        Section(
            title = "Accessibility".to_string(),
            intro = "The data model and native mapping ship today; the authoring surface is the \
                gap.".to_string(),
        ) {
            Item(
                title = "Per-primitive accessibility API".to_string(),
                status = "Planned".to_string(),
                tone = planned(),
            ) {
                Typography(
                    content = "An ergonomic way to set accessibility props \u{2014} label, \
                        role, traits, actions \u{2014} on any primitive, via a \
                        .accessibility(...) builder and a ui! prop, plus an author-facing \
                        announcement call. Every backend already maps the props to native AX \
                        (UIAccessibility, AccessibilityNodeInfo, ARIA); this closes the \
                        author-side surface.".to_string(),
                    muted = true,
                )
            }
        }
    };

    let content = ui! {
        Stack(gap = StackGap::Xl) {
            PageHeader(
                title = "Roadmap",
                blurb = "What we're working toward next. This list is deliberately honest about what \
                 isn't finished yet \u{2014} the GitHub issue tracker has the detail; this is \
                 the high-level view.",
            )
            PageSection(handle = docs_ref) { docs_section }
            PageSection(handle = a11y_ref) { a11y_section }
        }
    };
    layout_with_toc(content, toc)
}

// =============================================================================
// Status chips. Keep the vocabulary small so the page reads at a glance:
//   In progress — actively being built
//   Planned     — committed, not started
// =============================================================================

fn in_progress() -> idea_ui::ToneRef {
    idea_ui::tone::Primary.into()
}
fn planned() -> idea_ui::ToneRef {
    idea_ui::tone::Neutral.into()
}

// =============================================================================
// Item — one roadmap entry: a title row with a status chip, then the
// body the caller passes as children.
// =============================================================================

#[derive(Default)]
pub struct ItemProps {
    pub title: String,
    pub status: String,
    pub tone: idea_ui::ToneRef,
    pub children: Vec<Element>,
}

#[component]
pub fn Item(props: ItemProps) -> Element {
    let title = props.title;
    let status = props.status;
    let tone = props.tone;
    let children = props.children;
    ui! {
        Stack(gap = StackGap::Sm) {
            Stack(gap = StackGap::Sm, axis = StackAxis::Row) {
                Typography(content = title, kind = typography_kind::H3)
                Tag(label = status, tone = tone, variant = idea_ui::variant::Soft)
            }
            children
        }
    }
}

// =============================================================================
// Section — H2 title + intro, then the caller-supplied items as children.
// =============================================================================

#[derive(Default)]
pub struct SectionProps {
    pub title: String,
    pub intro: String,
    pub children: Vec<Element>,
}

#[component]
pub fn Section(props: SectionProps) -> Element {
    let title = props.title;
    let intro = props.intro;
    let children = props.children;
    ui! {
        Stack(gap = StackGap::Lg) {
            Typography(content = title, kind = typography_kind::H2)
            Typography(content = intro, muted = true)
            children
        }
    }
}

